# Roundhouse shell profile — sourced by bootstrap for .bashrc and /etc/profile.d
PACK_TUI_COMMAND="roundhouse tui"

PACK_ALIASES='
alias rh="roundhouse"
'

PACK_BANNER_NAME="Roundhouse Agent Environment"
PACK_BANNER_EMOJI="🎯"
PACK_BANNER_COMMANDS='
  roundhouse tui        → Open agent TUI
  roundhouse status     → Show daemon status
  roundhouse logs       → Tail daemon logs
  roundhouse restart    → Restart the daemon
  roundhouse config     → Show configuration
'
